function getTranslatedOrigin(origin, lang) {
  return (i18n.origins[lang] && i18n.origins[lang][origin]) || origin;
}
function getTranslatedSize(size, lang) {
  return (i18n.sizes[lang] && i18n.sizes[lang][size]) || size;
}
function getTranslatedGroup(group, lang) {
  return (i18n.groups[lang] && i18n.groups[lang][group]) || group;
}
function getTranslatedLifespan(lifespan, lang) {
  if (!i18n.lifespan[lang]) return lifespan;
  return lifespan.replace(/years/g, i18n.lifespan[lang]);
}
